// Validation helpers
function isValidIndexName(name) {
  if (!name || typeof name !== 'string') return false;
  // Allow alphanumeric, hyphens, underscores, dots, and wildcards for pattern matching
  const validPattern = /^[a-zA-Z0-9_\-.*]+$/;
  if (!validPattern.test(name)) return false;
  // Prevent path traversal
  if (name.includes('..')) return false;
  // Max length check
  if (name.length > 255) return false;
  return true;
}

function isSystemIndex(name) {
  // Block access to Elasticsearch internal indices
  const blockedPrefixes = ['.security', '.kibana', '.apm', '.tasks', '.async-search', '.monitoring'];
  const lowerName = name.toLowerCase();
  for (const prefix of blockedPrefixes) {
    if (lowerName.startsWith(prefix)) return true;
  }
  return false;
}

